CustomField.formula:
"W" & 
IF(
    LEN(
        TEXT(
            IF(
                CEILING((ReportDate__c - DATE(YEAR(ReportDate__c), 1, 1) + 1) / 7) > 52,
                52,
                CEILING((ReportDate__c - DATE(YEAR(ReportDate__c), 1, 1) + 1) / 7)
            )
        )
    ) = 1,
    "0" & TEXT(
        IF(
            CEILING((ReportDate__c - DATE(YEAR(ReportDate__c), 1, 1) + 1) / 7) > 52,
            52,
            CEILING((ReportDate__c - DATE(YEAR(ReportDate__c), 1, 1) + 1) / 7)
        )
    ),
    TEXT(
        IF(
            CEILING((ReportDate__c - DATE(YEAR(ReportDate__c), 1, 1) + 1) / 7) > 52,
            52,
            CEILING((ReportDate__c - DATE(YEAR(ReportDate__c), 1, 1) + 1) / 7)
        )
    )
)
